/* StandardCategoryCommandMyBatisDao.updatePrStdCtg */
UPDATE PR_STD_CTG
SET    STD_CTG_NM           = #{stdCtgNm}
  , USE_YN               = #{useYn}
  , SORT_SEQ             = #{sortSeq}
  , LEAF_CTG_YN          = #{leafCtgYn}
  , SAFE_CERTI_NEED_YN   = #{safeCertiNeedYn}
  , MD_ID                = #{mdId}
  , GOODS_NOTI_LISART_CD = #{goodsNotiLisartCd}
  , HS_CD                = #{hsCd}
  , MRGN_RATE            = #{mrgnRate}
  , SAM_MARKET_YN        = #{samMarketYn}
  , SYS_MOD_ID           = 'admin'
  , SYS_MOD_DTM          = NOW()
WHERE STD_CTG_NO = #{stdCtgNo}

